from crewai.tools import tool
import json

@tool("calculate_bmi")
def calculate_bmi(weight_kg: float, height_m: float) -> str:
    """
    Calculate the Body Mass Index (BMI) from weight and height.
    Returns a JSON string with the BMI value and category.

    Args:
        weight_kg: Body weight in kilograms.
        height_m: Height in metres.
    """
    if height_m <= 0:
        return json.dumps({"error": "Height must be greater than zero."})
    bmi = weight_kg / (height_m ** 2)
    if bmi < 18.5:
        category = "Underweight"
    elif bmi < 25:
        category = "Normal weight"
    elif bmi < 30:
        category = "Overweight"
    else:
        category = "Obese"
    return json.dumps({"bmi": round(bmi, 1), "category": category})

# Use in an agent:
# Agent(role="Health Advisor", ..., tools=[calculate_bmi])

from crewai import Agent, Crew, Task
from crewai.project import CrewBase, agent, crew, task
from langchain_openai import ChatOpenAI

@CrewBase
class ResearchCrew:
    agents_config = "config/agents.yaml"
    tasks_config = "config/tasks.yaml"

    @agent
    def researcher(self) -> Agent:
        return Agent(
            config=self.agents_config["researcher"],
            llm=ChatOpenAI(model="gpt-4o-mini"),
            verbose=True,
        )

    @agent
    def writer(self) -> Agent:
        return Agent(
            config=self.agents_config["writer"],
            llm=ChatOpenAI(model="gpt-4o-mini"),
        )
